package business;

import dao.RoomDAO;
import dao.EquipmentDAO;
import dao.UserDAO;
import dao.impl.RoomDAOImpl;
import dao.impl.EquipmentDAOImpl;
import dao.impl.UserDAOImpl;
import model.Room;
import model.Equipment;
import model.User;
import model.enums.Role;
import util.PasswordHash;

import java.util.List;

public class AdminService {
    private RoomDAO roomDAO = new RoomDAOImpl();
    private EquipmentDAO equipmentDAO = new EquipmentDAOImpl();
    private UserDAO userDAO = new UserDAOImpl();

    // ============== Quản lý Phòng họp ==============
    public boolean addRoom(String name, int capacity) {
        Room room = new Room();
        room.setName(name);
        room.setCapacity(capacity);
        room.setStatus("AVAILABLE");
        return roomDAO.insert(room);
    }

    public List<Room> getAllRooms() {
        return roomDAO.findAll();
    }

    public boolean updateRoom(int id, String name, int capacity) {
        return roomDAO.update(id, name, capacity);
    }

    public boolean deleteRoom(int id) {
        return roomDAO.delete(id);
    }

    // ============== Quản lý Thiết bị ==============
    public boolean updateEquipmentQuantity(int equipmentId, int quantity) {
        return equipmentDAO.updateQuantity(equipmentId, quantity);
    }

    // ============== Quản lý Người dùng ==============
    public boolean createSupportStaff(String name, String email, String password) {
        User user = new User();
        user.setName(name);
        user.setEmail(email);
        user.setPassword(PasswordHash.hashPassword(password));
        user.setRole(Role.SUPPORT);
        return userDAO.insert(user);
    }

    public boolean createEmployee(String name, String email, String password) {
        User user = new User();
        user.setName(name);
        user.setEmail(email);
        user.setPassword(PasswordHash.hashPassword(password));
        user.setRole(Role.EMPLOYEE);
        return userDAO.insert(user);
    }
}
